import{_ as i,c as a,a as s,o as t}from"./app-CEcM0piI.js";const r={};function n(h,e){return t(),a("div",null,e[0]||(e[0]=[s('<p>协程就是一段可以挂起（suspend）和恢复（resume）的程序，一般而言，就是一个支持挂起和恢复的函数。</p><p>在C++中 函数定义包含了 co_await, co_yield , co_return 三个关键字的其一就是是协程。</p><p>能被多次调用的函数，每次只运行协程代码的一部分 每次调用之间本地变量和参数都会被保存，生命周期与调用者无关 本地变量和参数一般是在堆区保存,但在C++中也可以自己指定保存的区域</p><p>与线程的区别：线程会互相争抢，（同一个线程上运行的）协程只会在主动让出控制权时切换</p><h2 id="关键对象" tabindex="-1"><a class="header-anchor" href="#关键对象"><span>关键对象</span></a></h2><h3 id="promise-type" tabindex="-1"><a class="header-anchor" href="#promise-type"><span>promise_type</span></a></h3><p>对协程行为的配置 (比如是否在协程入口处挂起) 用于调用者与协程之间的数据传递 可以对协程对象增加一些自定义数据结构 (用于实现调度器)</p><h3 id="coroutine-handle-promise-type" tabindex="-1"><a class="header-anchor" href="#coroutine-handle-promise-type"><span>coroutine_handle&lt;promise_type&gt;</span></a></h3><p>外部操作协程的接口 (本质上是一个指针)</p><p>其中co_await是个关键字，它的出现，通常来说就会使得当前函数（协程）的执行被挂起。一般不是因为当前执行的线程被阻塞了，而是当前函数（协程）执行的位置被存起来，在将来某个时间点又读取出来继续执行的。 相当于其他语言的await</p><p>协程的挂起是协程的灵魂。C++通过co_await表达式来处理协程的挂起，表达式的操作对象则为等待体（awaiter）。</p><h3 id="coroutine-interface" tabindex="-1"><a class="header-anchor" href="#coroutine-interface"><span>coroutine_interface</span></a></h3><p>是coroutine的返回对象,对coroutine_handle的封装 在coroutine_handle的基础上再实现一些用户自定义的接口，比如获取返回值等 协程的返回值必须是coroutine_interface对象</p><h3 id="awaitor" tabindex="-1"><a class="header-anchor" href="#awaitor"><span>awaitor</span></a></h3><p>控制协程在挂起时的行为 决定是否挂起 决定把控制权交给谁 配置在控制器返回时做什么</p><h2 id="关键字" tabindex="-1"><a class="header-anchor" href="#关键字"><span>关键字</span></a></h2><h3 id="co-await" tabindex="-1"><a class="header-anchor" href="#co-await"><span><strong>co_await</strong></span></a></h3><p><code>co_await</code>调用一个awaiter对象（可以认为是一个接口），根据其内部定义决定其操作是挂起，还是继续，以及挂起，恢复时的行为。其呈现形式为</p><div class="language-cpp line-numbers-mode" data-highlighter="shiki" data-ext="cpp" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">cw_ret </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> co_await</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">  awaiter</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>cw_ret 记录调用的返回值，其是awaiter的await_resume 接口返回值。</p><h3 id="co-yield" tabindex="-1"><a class="header-anchor" href="#co-yield"><span><strong>co_yield</strong></span></a></h3><p>挂起协程。其出现形式是</p><div class="language-cpp line-numbers-mode" data-highlighter="shiki" data-ext="cpp" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">co_yield</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">  cy_ret</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>cy_ret会保存在promise承诺对象中（通过<code>yield_value</code>函数）。在协程外部可以通过promise得到。</p><h3 id="co-return" tabindex="-1"><a class="header-anchor" href="#co-return"><span><strong>co_return</strong></span></a></h3><p>协程返回。其出现形式是</p><div class="language-cpp line-numbers-mode" data-highlighter="shiki" data-ext="cpp" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">co_return</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> cr_ret</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>cr_ret会保存在promise承诺对象中（通过<code>return_value</code>函数）。在协程外部可以通过promise得到。要注意，cr_ret并不是协程的返回值。这个是有区别的。</p>',28)]))}const d=i(r,[["render",n]]),c=JSON.parse('{"path":"/base/os/6/","title":"6 协程","lang":"zh-CN","frontmatter":{"title":"6 协程","createTime":"2025/06/22 10:44:52","permalink":"/base/os/6/"},"readingTime":{"minutes":2.27,"words":682},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/操作系统/6 协程.md","headers":[]}');export{d as comp,c as data};
